using System;
using System.Diagnostics;
using System.IO;
using System.Runtime.InteropServices;
using SkiaSharp;

Console.WriteLine($"OS: {RuntimeInformation.OSDescription}");
Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");

// Generate large JPEG (4000x3000 = 12MP)
var largePath = "large-test.jpg";
using (var bmp = new SKBitmap(4000, 3000)) {
    using var canvas = new SKCanvas(bmp);
    var rng = new Random(42);
    for (int y = 0; y < 3000; y += 10)
        for (int x = 0; x < 4000; x += 10) {
            using var paint = new SKPaint();
            paint.Color = new SKColor((byte)rng.Next(256), (byte)rng.Next(256), (byte)rng.Next(256));
            canvas.DrawRect(x, y, 10, 10, paint);
        }
    using var img = SKImage.FromBitmap(bmp);
    using var enc = img.Encode(SKEncodedImageFormat.Jpeg, 90);
    using var fs = File.OpenWrite(largePath);
    enc.SaveTo(fs);
}

using var data = SKData.Create(largePath);
var sw = new Stopwatch();
using (var w = SKBitmap.Decode(data)) { using var e = w.Encode(SKEncodedImageFormat.Jpeg, 90); }

const int iterations = 10;
double totalDecode = 0, totalEncode = 0;
for (int i = 0; i < iterations; i++) {
    sw.Restart(); var bitmap = SKBitmap.Decode(data); sw.Stop();
    totalDecode += sw.Elapsed.TotalMilliseconds;
    sw.Restart(); var outputData = bitmap.Encode(SKEncodedImageFormat.Jpeg, 90); sw.Stop();
    totalEncode += sw.Elapsed.TotalMilliseconds;
    outputData.Dispose(); bitmap.Dispose();
}
Console.WriteLine($"Avg decode: {totalDecode/iterations:F1}ms");
Console.WriteLine($"Avg encode: {totalEncode/iterations:F1}ms");
Console.WriteLine($"Avg round-trip: {(totalDecode+totalEncode)/iterations:F1}ms");
Console.WriteLine("SUCCESS: benchmark completed");
